import{_ as a,o as t,c as b,j as r,a as n,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"怎样腌菜","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/4.术法/魔法/法术书/怎样腌菜.md","filePath":"4.资源分区/4.术法/魔法/法术书/怎样腌菜.md"}'),o={name:"4.资源分区/4.术法/魔法/法术书/怎样腌菜.md"};function d(l,e,_,i,p,c){return t(),b("div",null,[...e[0]||(e[0]=[r("h1",{id:"怎样腌菜",tabindex:"-1"},[n("怎样腌菜 "),r("a",{class:"header-anchor",href:"#怎样腌菜","aria-label":'Permalink to "怎样腌菜"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：新世短歌034")])])],-1),s('<h1 id="怎样腌菜-1" tabindex="-1">怎样腌菜 <a class="header-anchor" href="#怎样腌菜-1" aria-label="Permalink to &quot;怎样腌菜&quot;">​</a></h1><p>怎样腌菜<br> 法术书<br> D+500<br> 本质：魔幻本质<br> 封面上绘画出了上古灵植的幻影。每一片叶片都似蕴含着天地灵气，其上点缀着橙色的浓缩的灵阳印记，但书的名字是...怎样腌菜？<br> 怎样腌菜为你的施法提供了一些法术特质与一个特殊的法术。<br> 【人与时光与自然】：充满关于自然变化的知识让你进一步领会到了自然的真谛，你如果不具有自然派系造诣，则获得D级自然派系造诣。<br> 【乳酸】：乳酸菌发酵带来的酸味，应用在法术上便使法术拥有了一定腐蚀性的特质，你释放的法术具有【熔毁】2。<br> 【盐腌】：盐是洁净而又基础的物质，也是腌制的基础，你获得额外的一种法术增幅方式：消耗2点能量，使释放的法术具有更强的驱魔效果，提供2点破魔。<br> 【自时天成】：腌菜的方式还是要由自己掌握，与自然，时间，材料共同组成一场生命的共鸣曲，将精神投入其中，成为其中的一部分，你选择一个魔法副专业，包括其的检定获得等同于其人物内在支线等级*2的增强检定加值。</p><p>腌姜<br> D+500<br> 可重复购买，但需选择不同的选项 <br> 类型：？<br> 等级：D <br> 派系：自然<br> 花费：2<br> 成分：？<br> 动作：？<br> 射程：无 <br> 目标：？<br> 持续：？<br> 生姜可以伪装成几乎任何的食物，何况是腌过的生姜！<br> 你从以下选项中选择一个获得<br> 土豆条：选择一个核心派系的价格D+500的法术，你将其作为自然派系的法术释放<br> 胡萝卜片：选择一个咒击派系的价格D+500的法术，你将其作为自然派系的法术释放<br> 冰激淋：选择一个黑暗派系的价格D+500的法术，你将其作为自然派系的法术释放<br> 蒜泥：选择一个物理派系的价格D+500的法术，你将其作为自然派系的法术释放<br> 樱花瓣：选择一个万变派系的价格D+500的法术，你将其作为自然派系的法术释放</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',5)])])}const D=a(o,[["render",d]]);export{f as __pageData,D as default};
